import React, { useState, useEffect } from 'react';
import ExpenseService from '../services/ExpenseService';

const ExpenseList = () => {
    const [expenses, setExpenses] = useState([]);
    const [loading, setLoading] = useState(true);
    const [message, setMessage] = useState({ text: '', type: '' });
    const [searchTerm, setSearchTerm] = useState('');
    const [filterType, setFilterType] = useState('');

    useEffect(() => {
        fetchExpenses();
    }, []);

    const fetchExpenses = async () => {
        try {
            const response = await ExpenseService.getAllExpenses();
            setExpenses(response.data);
        } catch (error) {
            setMessage({ text: '❌ Failed to load expenses.', type: 'error' });
            console.error('Error fetching expenses:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this expense?')) return;

        try {
            await ExpenseService.deleteExpense(id);
            setExpenses(prev => prev.filter(e => e.id !== id));
            setMessage({ text: '✅ Expense deleted successfully.', type: 'success' });
            setTimeout(() => setMessage({ text: '', type: '' }), 3000);
        } catch (error) {
            setMessage({ text: '❌ Failed to delete expense.', type: 'error' });
            console.error('Error deleting expense:', error);
        }
    };

    const uniqueTypes = [...new Set(expenses.map(e => e.expenseType))];

    const filtered = expenses.filter(e => {
        const matchSearch =
            e.projectName.toLowerCase().includes(searchTerm.toLowerCase()) ||
            e.vendor.toLowerCase().includes(searchTerm.toLowerCase()) ||
            (e.description && e.description.toLowerCase().includes(searchTerm.toLowerCase()));
        const matchType = filterType ? e.expenseType === filterType : true;
        return matchSearch && matchType;
    });

    const totalFiltered = filtered.reduce((sum, e) => sum + (e.amount || 0), 0);

    if (loading) return <div className="loading">Loading expenses...</div>;

    return (
        <div className="expense-list">
            <h2 className="page-title">📋 Expense Records</h2>

            {message.text && (
                <div className={`alert alert-${message.type}`}>
                    {message.text}
                </div>
            )}

            {/* Filters */}
            <div className="filters-bar">
                <input
                    type="text"
                    className="search-input"
                    placeholder="🔍 Search by project, vendor, description..."
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                />
                <select
                    className="filter-select"
                    value={filterType}
                    onChange={e => setFilterType(e.target.value)}
                >
                    <option value="">All Types</option>
                    {uniqueTypes.map(type => (
                        <option key={type} value={type}>{type}</option>
                    ))}
                </select>
                <div className="total-badge">
                    Showing {filtered.length} records | Total: ₹{totalFiltered.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                </div>
            </div>

            {filtered.length === 0 ? (
                <div className="empty-state">
                    <p>📭 No expenses found. Try a different search or add new expenses.</p>
                </div>
            ) : (
                <div className="table-wrapper">
                    <table className="expense-table">
                        <thead>
                            <tr>
                                <th>#</th>
                                <th>Project Name</th>
                                <th>Expense Type</th>
                                <th>Amount (₹)</th>
                                <th>Vendor</th>
                                <th>Date</th>
                                <th>Description</th>
                                <th>Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filtered.map((expense, index) => (
                                <tr key={expense.id}>
                                    <td>{index + 1}</td>
                                    <td><strong>{expense.projectName}</strong></td>
                                    <td><span className="badge">{expense.expenseType}</span></td>
                                    <td className="amount-cell">
                                        ₹{expense.amount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                                    </td>
                                    <td>{expense.vendor}</td>
                                    <td>{expense.date}</td>
                                    <td className="desc-cell">{expense.description || '—'}</td>
                                    <td>
                                        <button
                                            className="btn btn-danger btn-sm"
                                            onClick={() => handleDelete(expense.id)}
                                        >
                                            🗑️ Delete
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                        <tfoot>
                            <tr className="total-row">
                                <td colSpan="3"><strong>Grand Total</strong></td>
                                <td className="amount-cell">
                                    <strong>₹{totalFiltered.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</strong>
                                </td>
                                <td colSpan="4"></td>
                            </tr>
                        </tfoot>
                    </table>
                </div>
            )}
        </div>
    );
};

export default ExpenseList;
